mapper.select:
SELECT tag_id, tag_name FROM sys_tag
WHERE owner_user_id = #{userId} AND tag_key = #{tagKey}
    LIMIT 1

select tag_id as tagId, owner_user_id as ownerUserId, tag_name as tagName, tag_key as tagKey
from sys_tag
where owner_user_id = #{userId}
  and tag_name = #{tagName}
  and del_flag = '0'
    limit 1
